void showSimpleNotification() async {
  const AndroidNotificationDetails androidDetails = AndroidNotificationDetails('channel_id', 'channel_name', importance: Importance.high);
  const NotificationDetails platformDetails = NotificationDetails(android: androidDetails);
  await flutterLocalNotificationsPlugin.show(0, 'Rappel', 'Pensez à boire de l’eau', platformDetails);
}

void scheduleReminder(int id, DateTime deadline, String title) async {
  final scheduledTime = deadline.subtract(Duration(minutes: 10));
  const AndroidNotificationDetails androidDetails = AndroidNotificationDetails('task_channel', 'Rappels tâches', payload: 'task_$id');
  const NotificationDetails platformDetails = NotificationDetails(android: androidDetails);
  await flutterLocalNotificationsPlugin.zonedSchedule(id, 'Tâche à échoir', 'La tâche "$title" arrive bientôt', scheduledTime, platformDetails,
      androidAllowWhileIdle: true, uiLocalNotificationDateInterpretation: UILocalNotificationDateInterpretation.absoluteTime);
}
